steps.solution:
user = {"name": "alex", "age": 34}

def safe_get(d, key):
    if key in d:
        return d[key]
    return "missing"

print(safe_get(user, "name"))
print(safe_get(user, "email"))

def get_price(item):
    if item is None:
        return 0.0
    raw = item.get("price", "")
    if raw == "":
        return 0.0
    return float(raw)

print(get_price({"price": "29.99"}))
print(get_price({"name": "widget"}))
print(get_price({"price": ""}))
print(get_price(None))

